--
-- Table structure for table `inventory`
--

DROP TABLE IF EXISTS `inventory`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `inventory` (
  `inventory_id` bigint(20) NOT NULL COMMENT 'Die Inventarisierungsnummer des entsprechenden inventarisierten Artikels. Kann bis zu 12 Stellen lang sein, daher BIGINT statt INT als Datentyp',
  `order_id` int(10) unsigned NOT NULL COMMENT 'Die Bestellung, zu welcher dieser inventarisierte Artikel gehört',
  `inventory_name` varchar(255) NOT NULL COMMENT 'Artikelname, z.B. Unity-Pro-Lizenzen',
  `inventory_room` varchar(10) NOT NULL COMMENT 'Der Raum, in welchem sich dieser Artikel befindet',
  `inventory_count` int(10) unsigned NOT NULL DEFAULT '1' COMMENT 'Artikel-Anzahl, wieviele dieser Artikel mit dieser Inventarnummer auf einmal versehen werden',
  `inventory_date` date NOT NULL COMMENT 'Tag der Inventarisierung, wann der Artikel in die Inventarliste aufgenommen wurde',
  `inventory_serial_number` varchar(255) DEFAULT NULL COMMENT 'Eine optionale Seriennummer des Artikels, kann beliebige Formate annehme, primär bei Hardwareartikeln wichtig.',
  `inventory_license_key` varchar(255) DEFAULT NULL COMMENT 'optionaler Lizenzschlüssel, z.B. bei Softwarelizenzen',
  `inventory_responsible_person` varchar(255) DEFAULT NULL COMMENT 'Eingetragene Person, welche für den Artikel verantwortlich ist, bzw diesen verwendet. Entweder z.B. der Professor, für den dieser Artikel bestellt wurde, oder oder Mitarbeiter, welcher sich um diesen Artikel kümmert.',
  `inventory_comment` varchar(255) DEFAULT NULL COMMENT 'optionaler Kommentar für allerlei',
  PRIMARY KEY (`inventory_id`),
  KEY `inventory_order_fk_idx` (`order_id`),
  CONSTRAINT `inventory_order_fk1` FOREIGN KEY (`order_id`) REFERENCES `order` (`order_id`) ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='Repräsentation eines Eintrages in der Inventarisierungsliste';
/*!40101 SET character_set_client = @saved_cs_client */;

