  `invoice_date` date NOT NULL COMMENT 'Tag der Rechnungserstellung',
  `invoice_comment` varchar(255) DEFAULT NULL COMMENT 'optionaler Kommentar',
  `invoice_created_date` datetime NOT NULL,
  PRIMARY KEY (`invoice_id`),
  KEY `invoice_order_fk_idx` (`order_id`,`cost_center_id`),
  CONSTRAINT `invoice_order_fk` FOREIGN KEY (`order_id`, `cost_center_id`) REFERENCES `order` (`order_id`, `secondary_cost_center_id`) ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='Repräsentation einer Rechnung, welche einer Bestellung zugeordnet wird.';
