DROP TABLE IF EXISTS `item`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `item` (
  `order_id` int(10) unsigned NOT NULL COMMENT 'Interne Bestellungsnummer',
  `item_id` smallint(5) unsigned NOT NULL COMMENT 'Innerhalb einer Bestellnummer fortlaufende Zahl zur Nummerierung der Bestellpositionen',
  `item_name` text NOT NULL COMMENT 'Name des Artikels',
  `item_price_per_unit` decimal(10,2) NOT NULL COMMENT 'Preis pro Artikel (netto)',
  `item_quantity` int(10) unsigned NOT NULL DEFAULT '1' COMMENT 'Menge (in quantitiy_unit Einheiten)',
  `item_quantity_unit` varchar(45) DEFAULT NULL COMMENT 'Mengenangabe dieses Artikels (Stück, Kilogramm, Gramm, Liter, etc)',
  `item_article_id` varchar(255) DEFAULT NULL COMMENT 'optionale Artikelnummer des Lieferanten',
  `item_comment` varchar(255) DEFAULT '' COMMENT 'optionaler Kommentar',
  `vat_value` decimal(2,0) unsigned NOT NULL COMMENT 'der für diese Bestellposition gültige Mehrwertsteuersatz',
  `preferred_list_abbr` char(2) DEFAULT NULL COMMENT 'Falls dieser Artikel auf einer Vorzugsliste geführt wird, gibt dieses Attribut die entsprechende Liste an',
  `item_preferred_list_number` varchar(20) DEFAULT NULL COMMENT 'Nummerierung innerhalb der Liste, falls dieser Artikel auf einer Vorzugsliste geführt wird.',
  `item_vat_type` enum('netto','brutto') NOT NULL DEFAULT 'netto',
  PRIMARY KEY (`order_id`,`item_id`),
  KEY `item_order_fk_idx` (`order_id`) USING BTREE,
  KEY `item_vat_fk_idx` (`vat_value`),
  KEY `item_preferred_list_fk_idx` (`preferred_list_abbr`),
  CONSTRAINT `item_order_fk` FOREIGN KEY (`order_id`) REFERENCES `order` (`order_id`) ON UPDATE CASCADE,
  CONSTRAINT `item_preferred_list_fk` FOREIGN KEY (`preferred_list_abbr`) REFERENCES `preferred_list` (`preferred_list_abbr`) ON UPDATE CASCADE,
  CONSTRAINT `item_vat_fk` FOREIGN KEY (`vat_value`) REFERENCES `vat` (`vat_value`) ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='Repräsentation einer einzelnen Bestellposition innerhalb einer Bestellung';
/*!40101 SET character_set_client = @saved_cs_client */;

