--
-- Table structure for table `log`
--

DROP TABLE IF EXISTS `log`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `log` (
  `log_id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `log_entry_time` datetime NOT NULL,
  `log_entry` text NOT NULL,
  `user_name` varchar(255) NOT NULL,
  PRIMARY KEY (`log_id`),
  KEY `log_user_fk_idx` (`user_name`),
  CONSTRAINT `log_user_fk` FOREIGN KEY (`user_name`) REFERENCES `user` (`user_name`) ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `log`
--

LOCK TABLES `log` WRITE;
/*!40000 ALTER TABLE `log` DISABLE KEYS */;
/*!40000 ALTER TABLE `log` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `order`
--

DROP TABLE IF EXISTS `order`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `order` (
  `order_id` int(10) unsigned NOT NULL AUTO_INCREMENT COMMENT 'Intern eindeutig identifizierende Kennnummer der Bestellung.\nAls ID wird eine automatisch generierte und inkrementierte Zahl gewählt, da sich die Bestandteile der eigentlichen Bestellnummer, welche auf dem Formular abgedruckt wird, im Laufe der Zeit ändern können (Kostenstelle/Jahr kann sich nachträglich ändern).',
  `primary_cost_center_id` varchar(20) NOT NULL COMMENT 'Die primäre Kostenstelle, welche in die Generierung der Bestellnummer auf dem Formular einfließt und vor allem zur übersichtlichen Einsortierung in entsprechende Archivierungssysteme (Ordner) dient.',
  `primary_cost_center_faculty` varchar(10) NOT NULL COMMENT 'Die Fakultät der primären Kostenstelle. zB IT',
  `order_booking_year` char(2) NOT NULL COMMENT 'Jahr, in dem die Bestellung einsortiert werden soll. zB 2013, 1998, etc',
  `order_auto_index` smallint(6) NOT NULL COMMENT 'Innerhalb einer primären Kostenstelle und Jahres fortlaufende Nummer. Bildet die letzten drei Stellen der endgültigen Bestellnummer.',
  `order_created_date` datetime NOT NULL COMMENT 'Zeitangabe, wann die Bestellung erstellt wurde.',
  `order_legacy_alias` char(2) DEFAULT NULL COMMENT 'Dieser Wert beinhaltet das Kürzel der Mitarbeiter aus dem alten System und wird zur Generierung der alten Bestellformulare verwendet',
  `owner_user_name` varchar(255) NOT NULL COMMENT 'Benutzerkennung des anlegenden Benutzers.',
  `order_content_description` varchar(255) NOT NULL COMMENT 'Eine kurze Beschreibung des Bestellinhaltes, dient primär als grobe Orientierung für eine Suche nach bestimmten Bestellungen.',
  `order_status` varchar(20) NOT NULL COMMENT 'Der Status in dem sich die Bestellung derzeit befindet.',
  `currency_short` char(3) NOT NULL COMMENT 'Verwendete Währung dieser Bestellung (Kurzform)',
  `order_comment` varchar(255) DEFAULT '' COMMENT 'Ein optionaler Kommentar als Randnotiz im Rahmen des Bestellsystemes. Wird nicht auf das Formular gedruckt.',
  `order_comment_for_supplier` text COMMENT 'Ein optionaler Kommentar für den Lieferanten, welcher mit auf das Bestellformular gedruckt wird.',
  `order_quote_number` varchar(255) DEFAULT NULL,
  `order_quote_sign` varchar(255) DEFAULT NULL,
  `order_quote_date` date DEFAULT NULL,
  `order_quote_price` decimal(10,2) DEFAULT NULL,
  `delivery_person_id` int(10) unsigned NOT NULL COMMENT 'Personenkennung des Empfängers, verweist auf einen Personeneintrag, hinter welchem die Adresse, Name, Telefon, etc. abgelegt sind.',
  `invoice_person_id` int(10) unsigned NOT NULL COMMENT 'Personenkennung des Rechnungsempfängers, verweist auf einen Personeneintrag, hinter welchem die Adresse, Name, Telefon, etc. abgelegt sind.',
  `queries_person_id` int(10) unsigned NOT NULL COMMENT 'Personenkennung des Verantwortlichen für Rückfragen, verweist auf einen Personeneintrag, hinter welchem der Name, Telefon, etc. abgelegt sind.',
  `supplier_name` varchar(255) NOT NULL COMMENT 'Name des Lieferanten',
  `customer_id` varchar(255) DEFAULT '' COMMENT 'Optionale Kundennummer',
  `secondary_cost_center_id` varchar(20) NOT NULL COMMENT 'Sekundäre Kostenstelle, welche die zu belastende Kostenstelle angibt.',
  `order_fixed_discount` decimal(10,2) unsigned DEFAULT '0.00' COMMENT 'Optional gewährter Festbetrag-Rabatt auf die gesammte Netto-Summe der Bestellung',
  `order_percentage_discount` decimal(4,2) unsigned DEFAULT '0.00' COMMENT 'Optional gewährter Rabatt auf die gesammte Netto-Summe der Bestellung (Abhängig vom Lieferanten), in XX,XX%',
  `order_cashback_percentage` decimal(3,2) unsigned DEFAULT NULL COMMENT 'Skonto Prozentsatz (in X.XX%)',
  `order_cashback_days` tinyint(3) unsigned DEFAULT NULL COMMENT 'Skonto Zeitraum in Tagen',
  `order_last_updated_time` datetime NOT NULL COMMENT 'Zeitpunkt der letzten Änderung',
  `order_flag_decision_cheapest_offer` tinyint(1) DEFAULT '0' COMMENT 'Auswahlmöglichkeit "[...] preisgünstigste und wirtschaftlichste Angebot [...]" auf Seite 2 des Bestellformularvordruckes, Punkt 4',
  `order_flag_decision_sole_supplier` tinyint(1) DEFAULT '0' COMMENT 'Auswahlmöglichkeit "[...] EinzelanbieterIn ist [...]" auf Seite 2 des Bestellformularvordruckes, Punkt 4',
  `order_flag_decision_contract_partner` tinyint(1) DEFAULT '0' COMMENT 'Auswahlmöglichkeit "[...] Rahmenvertragspartner ist [...]" auf Seite 2 des Bestellformularvordruckes, Punkt 4',
  `order_flag_decision_other_reasons` tinyint(1) DEFAULT '0' COMMENT 'Freitext-Auswahlmöglichkeit "[...] aus folgendem Grund bevorzugt wurde: [...]" auf Seite 2 des Bestellformularvordruckes, Punkt 4',
  `order_decision_other_reasons_description` text COMMENT 'Freitext zur Auswahlmöglichkeit "[...] aus folgendem Grund bevorzugt wurde: [...]" auf Seite 2 des Bestellformularvordruckes, Punkt 4',
  `order_flag_edv_permission` tinyint(1) DEFAULT '0' COMMENT 'Bestätigung, dass die Beschaffung mit dem RZ abgeklärt ist ( Punkt 5 Bestellformularvordruck Seite 2 ).',
  `order_flag_furniture_permission` tinyint(1) DEFAULT '0' COMMENT 'Bestätigung, dass die Beschaffung mit der TA abgeklärt ist ( Punkt 6 Bestellformularvordruck Seite 2).\n',
  `order_flag_furniture_room` tinyint(1) DEFAULT '0' COMMENT 'Bestätigung, dass der erforderliche Raum für die bestellten Möbel/Geräte zur Verfügung steht (Punkt 6 Bestellformularvordruck Seite 2)',
  `order_flag_investment_room` tinyint(1) DEFAULT '0' COMMENT 'Bestätigung, dass ein Raum für die Aufnahme der Geräte zur Verfügung steht, im Falle von Investments (Punkt 7 Bestellformularvordruck Seite 2)',
  `order_flag_investment_structural_measures` tinyint(1) DEFAULT '0' COMMENT 'Bestätigung, dass im Falle von baulichen Maßnahmen, entsprechende Abstimmungen mit der Technischen Abteilung stattgefunden haben und die Bestätigung dieser beiliegt (Punkt 7 Bestellformularvordruck Seite 2)',
  `order_flag_media_permission` tinyint(1) DEFAULT '0' COMMENT 'Bestätigung, dass die Zustimmung der Medientechnik beiliegt, falls diese benötigt wird (Punkt 8 Bestellformularvordruck Seite 2)',
  `order_dfg_key` varchar(45) DEFAULT NULL COMMENT 'optionaler DFG-Schlüssel bei Investitionen (Seite 2)',
  PRIMARY KEY (`order_id`),
  UNIQUE KEY `order_composite_unique` (`primary_cost_center_faculty`,`order_legacy_alias`,`primary_cost_center_id`,`order_booking_year`,`order_auto_index`) COMMENT 'Eine Kombination aus Fakultät, Kostenstelle, Jahr, Mitarbeiterkürzel (falls aus altem System übernommen) und Fortlaufender Nummer darf nur ein einziges Mal existieren.',
  KEY `order_status_fk_idx` (`order_status`),
  KEY `order_currency_fk_idx` (`currency_short`),
  KEY `order_secondary_cost_center_fk_idx` (`secondary_cost_center_id`),
  KEY `order_supplier_fk_idx` (`supplier_name`),
  KEY `order_customer_id_fk_idx` (`supplier_name`,`customer_id`),
  KEY `order_user_fk_idx` (`owner_user_name`),
  KEY `order_invoice_person_fk_idx` (`invoice_person_id`),
  KEY `order_delivery_person_fk_idx` (`delivery_person_id`),
  KEY `order_callback_person_fk_idx` (`queries_person_id`),
  KEY `order_fk_invoice_idx` (`order_id`,`secondary_cost_center_id`),
  KEY `order_last_updated_time_idx` (`order_last_updated_time`),
  KEY `order_primary_cost_center_fk` (`primary_cost_center_faculty`,`primary_cost_center_id`),
  CONSTRAINT `order_callback_person_fk` FOREIGN KEY (`queries_person_id`) REFERENCES `person` (`person_id`) ON UPDATE CASCADE,
  CONSTRAINT `order_cost_center_fk` FOREIGN KEY (`secondary_cost_center_id`) REFERENCES `cost_center` (`cost_center_id`) ON UPDATE CASCADE,
  CONSTRAINT `order_currency_fk` FOREIGN KEY (`currency_short`) REFERENCES `currency` (`currency_short`) ON UPDATE CASCADE,
  CONSTRAINT `order_customer_id_fk` FOREIGN KEY (`supplier_name`, `customer_id`) REFERENCES `customer_id` (`supplier_name`, `customer_id`) ON UPDATE CASCADE,
  CONSTRAINT `order_delivery_person_fk` FOREIGN KEY (`delivery_person_id`) REFERENCES `person` (`person_id`) ON UPDATE CASCADE,
  CONSTRAINT `order_invoice_person_fk` FOREIGN KEY (`invoice_person_id`) REFERENCES `person` (`person_id`) ON UPDATE CASCADE,
  CONSTRAINT `order_primary_cost_center_fk` FOREIGN KEY (`primary_cost_center_faculty`, `primary_cost_center_id`) REFERENCES `primary_cost_center` (`faculty_abbr`, `cost_center_id`) ON UPDATE CASCADE,
  CONSTRAINT `order_status_fk` FOREIGN KEY (`order_status`) REFERENCES `order_status` (`order_status`) ON UPDATE CASCADE,
  CONSTRAINT `order_supplier_fk` FOREIGN KEY (`supplier_name`) REFERENCES `supplier` (`supplier_name`) ON UPDATE CASCADE,
  CONSTRAINT `order_user_fk` FOREIGN KEY (`owner_user_name`) REFERENCES `user` (`user_name`) ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1570 DEFAULT CHARSET=utf8 COMMENT='Repräsentation einer Bestellung im Bestellsystem.';
