  `person_phone` varchar(45) DEFAULT NULL COMMENT 'optionale Telefonnummer',
  `person_title` varchar(45) DEFAULT NULL COMMENT 'optionaler Titel (Dipl. Ing. etc)',
  `person_comment` varchar(255) DEFAULT NULL COMMENT 'optionaler Kommentar',
  `address_name` varchar(255) NOT NULL COMMENT 'Name der Adresse',
  `faculty_abbr` varchar(10) DEFAULT NULL,
  PRIMARY KEY (`person_id`),
