  CONSTRAINT `person_address_fk` FOREIGN KEY (`address_name`) REFERENCES `address` (`address_name`) ON UPDATE CASCADE,
  CONSTRAINT `person_faculty_fk` FOREIGN KEY (`faculty_abbr`) REFERENCES `faculty` (`faculty_abbr`) ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=28 DEFAULT CHARSET=utf8 COMMENT='Repräsentation einer Person innerhalb des Bestellsystemes (Empfänger / Besteller / Kontakt / Benutzer )';
