--
-- Table structure for table `supplier`
--

DROP TABLE IF EXISTS `supplier`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `supplier` (
  `supplier_name` varchar(255) NOT NULL COMMENT 'Eindeutiger Name des Lieferanten (zB Conrad Electronics)',
  `supplier_phone` varchar(45) DEFAULT NULL COMMENT 'optionale Telefonnummer für eventuelle Kontaktaufnahmen',
  `supplier_fax` varchar(45) DEFAULT NULL COMMENT 'optionale Faxnummer für eventuelle Kontaktaufnahmen',
  `supplier_comment` varchar(255) DEFAULT NULL COMMENT 'optionaler Kommentar',
  `supplier_website` varchar(255) DEFAULT NULL COMMENT 'optionale Website des Lieferanten',
  `supplier_vat_id` varchar(20) DEFAULT NULL COMMENT 'Steuernummer',
  `supplier_flag_preferred` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Indikator, ob dieser Lieferant zu den Vorzugslieferanten gehört',
  `supplier_building_name` varchar(255) DEFAULT NULL,
  `supplier_street` varchar(255) NOT NULL,
  `supplier_building_number` varchar(255) DEFAULT NULL,
  `supplier_town` varchar(255) NOT NULL,
  `supplier_postal_code` varchar(255) NOT NULL,
  `supplier_county` varchar(255) DEFAULT NULL,
  `country_name` varchar(255) NOT NULL,
  `address_type` varchar(20) NOT NULL,
  `supplier_deactivated_date` date DEFAULT NULL,
  `supplier_cashback_percentage` decimal(3,2) unsigned DEFAULT NULL,
  `supplier_cashback_days` tinyint(3) unsigned DEFAULT NULL,
  PRIMARY KEY (`supplier_name`),
  KEY `supplier_country_fk_idx` (`country_name`),
  KEY `supplier_address_type_idx` (`address_type`),
  CONSTRAINT `supplier_address_type` FOREIGN KEY (`address_type`) REFERENCES `address_type` (`address_type`) ON UPDATE CASCADE,
  CONSTRAINT `supplier_country_fk` FOREIGN KEY (`country_name`) REFERENCES `country` (`country_name`) ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='Repräsentation eines Lieferanten';
/*!40101 SET character_set_client = @saved_cs_client */;

