--
-- Table structure for table `user`
--

DROP TABLE IF EXISTS `user`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `user` (
  `user_name` varchar(255) NOT NULL COMMENT 'Rechenzentrum HSE-Login',
  `person_id` int(10) unsigned NOT NULL COMMENT 'Referenz der Person, welche zugleich als Benutzer agiert',
  `preferred_cost_center_id` varchar(20) DEFAULT NULL COMMENT 'primär genutzte Kostenstelle zu Archivierungszwecken, z.B. das eigene Labor, auf welches dauernd bestellt wird.',
  PRIMARY KEY (`user_name`),
  UNIQUE KEY `person_id_UNIQUE` (`person_id`),
  KEY `preferred_cost_center_id_fk_idx` (`preferred_cost_center_id`),
  CONSTRAINT `preferred_cost_center_id_fk` FOREIGN KEY (`preferred_cost_center_id`) REFERENCES `cost_center` (`cost_center_id`) ON UPDATE CASCADE,
  CONSTRAINT `user_person_fk` FOREIGN KEY (`person_id`) REFERENCES `person` (`person_id`) ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='Benutzer des Bestellsystemes';
/*!40101 SET character_set_client = @saved_cs_client */;

